# ✅ BEST PRACTICE: Load once, cache for reuse
class CricketCommentaryBestPractice:
    def __init__(self):
        self.model = AutoModelForCausalLM.from_pretrained(
            'gpt2',
            load_in_8bit=True,  # Quantization from start
            device_map='auto'
        )
        self.tokenizer = AutoTokenizer.from_pretrained('gpt2')
        self.kv_cache = {}  # Persistent cache across batches

    def generate_commentary(self, ball_description):
        inputs = self.tokenizer(ball_description, return_tensors='pt')
        # past_key_values reuses computation from previous balls
        outputs = self.model.generate(
            inputs['input_ids'],
            max_length=50,
            use_cache=True,  # Enable KV-cache
            past_key_values=self.kv_cache.get(ball_description)
        )
        self.kv_cache[ball_description] = outputs.past_key_values
        return self.tokenizer.decode(outputs[0])
